import{_ as o,c as t,o as a,a1 as n}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Appendix | Clawdbot Tutorial","description":"Clawdbot appendix section: complete configuration reference, Gateway WebSocket API protocol, deployment options, and development guide.","frontmatter":{"title":"Appendix | Clawdbot Tutorial","sidebarTitle":"Appendix","subtitle":"Appendix","description":"Clawdbot appendix section: complete configuration reference, Gateway WebSocket API protocol, deployment options, and development guide.","tags":[],"order":340},"headers":[],"relativePath":"moltbot/moltbot/appendix/index.md","filePath":"moltbot/moltbot/appendix/index.md"}'),i={name:"moltbot/moltbot/appendix/index.md"};function r(l,e,s,p,d,c){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="appendix" tabindex="-1">Appendix <a class="header-anchor" href="#appendix" aria-label="Permalink to &quot;Appendix&quot;">​</a></h1><p>This section provides advanced reference documentation and development resources for Clawdbot, including complete configuration reference, Gateway WebSocket API protocol specification, deployment options, and development guide.</p><div class="info custom-block"><p class="custom-block-title">Target Audience</p><p>This section is suitable for users who need deep understanding of Clawdbot&#39;s internal mechanisms, perform advanced configuration, deploy, or participate in development. If you are just getting started, we recommend completing the <a href="./../../start/getting-started/">Quick Start</a> chapter first.</p></div><h2 id="subpage-navigation" tabindex="-1">Subpage Navigation <a class="header-anchor" href="#subpage-navigation" aria-label="Permalink to &quot;Subpage Navigation&quot;">​</a></h2><h3 id="complete-configuration-reference" tabindex="-1"><a href="./config-reference/">Complete Configuration Reference</a> <a class="header-anchor" href="#complete-configuration-reference" aria-label="Permalink to &quot;[Complete Configuration Reference](./config-reference/)&quot;">​</a></h3><p><strong>Detailed Configuration Reference</strong> - Covers all configuration options, default values, and examples. Find complete configuration documentation for Gateway, Agent, channels, tools, and other modules.</p><h3 id="gateway-websocket-api-protocol" tabindex="-1"><a href="./api-protocol/">Gateway WebSocket API Protocol</a> <a class="header-anchor" href="#gateway-websocket-api-protocol" aria-label="Permalink to &quot;[Gateway WebSocket API Protocol](./api-protocol/)&quot;">​</a></h3><p><strong>Protocol Specification Document</strong> - Complete specification for the Gateway WebSocket protocol, including endpoint definitions, message formats, authentication methods, and event subscription mechanisms. Ideal for developers who need to build custom clients or integrate with Gateway.</p><h3 id="deployment-options" tabindex="-1"><a href="./deployment/">Deployment Options</a> <a class="header-anchor" href="#deployment-options" aria-label="Permalink to &quot;[Deployment Options](./deployment/)&quot;">​</a></h3><p><strong>Deployment Method Guide</strong> - Deployment methods for different platforms: local installation, Docker, VPS, Fly.io, Nix, etc. Learn how to run Clawdbot in various environments.</p><h3 id="development-guide" tabindex="-1"><a href="./development/">Development Guide</a> <a class="header-anchor" href="#development-guide" aria-label="Permalink to &quot;[Development Guide](./development/)&quot;">​</a></h3><p><strong>Developer Documentation</strong> - Build from source, plugin development, testing, and contribution workflow. Learn how to participate in Clawdbot project development or write custom plugins.</p><h2 id="learning-path-recommendations" tabindex="-1">Learning Path Recommendations <a class="header-anchor" href="#learning-path-recommendations" aria-label="Permalink to &quot;Learning Path Recommendations&quot;">​</a></h2><p>Choose the appropriate learning path based on your needs:</p><h3 id="configuration-and-operations-personnel" tabindex="-1">Configuration and Operations Personnel <a class="header-anchor" href="#configuration-and-operations-personnel" aria-label="Permalink to &quot;Configuration and Operations Personnel&quot;">​</a></h3><ol><li>First read <a href="./config-reference/">Complete Configuration Reference</a> - Understand all configurable options</li><li>Refer to <a href="./deployment/">Deployment Options</a> - Choose the appropriate deployment solution</li><li>Consult Gateway WebSocket API documentation as needed for integration</li></ol><h3 id="application-developers" tabindex="-1">Application Developers <a class="header-anchor" href="#application-developers" aria-label="Permalink to &quot;Application Developers&quot;">​</a></h3><ol><li>Read <a href="./api-protocol/">Gateway WebSocket API Protocol</a> - Understand protocol mechanisms</li><li>View <a href="./config-reference/">Complete Configuration Reference</a> - Understand how to configure related functionality</li><li>Build clients based on protocol examples</li></ol><h3 id="plugin-feature-developers" tabindex="-1">Plugin/Feature Developers <a class="header-anchor" href="#plugin-feature-developers" aria-label="Permalink to &quot;Plugin/Feature Developers&quot;">​</a></h3><ol><li>Read <a href="./development/">Development Guide</a> - Understand development environment and build process</li><li>Deep dive into <a href="./api-protocol/">Gateway WebSocket API Protocol</a> - Understand Gateway architecture</li><li>Refer to <a href="./config-reference/">Complete Configuration Reference</a> - Understand configuration system</li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Prerequisites</p><p>Before diving into this section, it&#39;s recommended that you have completed:</p><ul><li>✅ Completed <a href="./../../start/getting-started/">Quick Start</a></li><li>✅ Configured at least one channel (such as <a href="./../../platforms/whatsapp/">WhatsApp</a> or <a href="./../../platforms/telegram/">Telegram</a>)</li><li>✅ Understood basic AI model configuration (see <a href="./../../advanced/models-auth/">AI Models and Authentication</a>)</li><li>✅ Have basic understanding of JSON configuration files and TypeScript</li></ul></div><h2 id="next-steps-guide" tabindex="-1">Next Steps Guide <a class="header-anchor" href="#next-steps-guide" aria-label="Permalink to &quot;Next Steps Guide&quot;">​</a></h2><p>After completing this section, you can:</p><ul><li><strong>Perform advanced configuration</strong> - Customize your Clawdbot by referring to <a href="./config-reference/">Complete Configuration Reference</a></li><li><strong>Deploy to production</strong> - Choose the appropriate deployment solution according to <a href="./deployment/">Deployment Options</a></li><li><strong>Develop custom features</strong> - Write plugins or contribute code by referring to <a href="./development/">Development Guide</a></li><li><strong>Deep dive into other features</strong> - Explore <a href="./../../advanced/">Advanced Features</a> sections, such as session management, tool system, etc.</li></ul><div class="tip custom-block"><p class="custom-block-title">Finding Help</p><p>If you encounter problems during use, consult <a href="./../../faq/troubleshooting/">Troubleshooting</a> for solutions to common issues.</p></div>',26)])])}const f=o(i,[["render",r]]);export{m as __pageData,f as default};
